logic [3:0] a;
logic [1:0] b;
logic signed [3:0] diff = a - b;
logic [4:0] out = $signed({diff, 1'b0});

logic signed [3:0] s;
logic [2:0] u;
logic [4:0] out;
assign u = s;  // asUInt cast
assign out = {1'b0, u};  // pad instead of sign-extend

logic [3:0] data;
logic [1:0] shift;
logic [3:0] shifted;
assign shifted = data << shift;  // dshl equivalent
